package com.example.app.waitlist;
import com.example.app.user.User; import com.example.app.session.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import org.springframework.web.server.ResponseStatusException; import org.springframework.http.HttpStatus; import java.time.*; import java.util.*;
@Service public class WaitlistService { private final WaitlistRequestRepository requests; private final WaitlistOfferRepository offers; private final BookingHoldRepository holds; private final WaitlistEventRepository events; public WaitlistService(WaitlistRequestRepository r,WaitlistOfferRepository o,BookingHoldRepository h,WaitlistEventRepository e){requests=r;offers=o;holds=h;events=e;} public List<WaitlistRequest> list(User me,String view){var s="history".equalsIgnoreCase(view)?List.of("BOOKED","DECLINED","EXPIRED","CANCELLED","REMOVED"):"offered".equalsIgnoreCase(view)?List.of("OFFERED"):List.of("ACTIVE"); return requests.findByCompanyIdAndStatusInOrderByJoinedAtAsc(me.getCompany().getId(),s);} public List<WaitlistEvent> history(User me,Long id){var r=get(me,id); return events.findByRequestIdOrderByCreatedAtDesc(r.getId());} private WaitlistRequest get(User me,Long id){return requests.findByIdAndCompanyId(id,me.getCompany().getId()).orElseThrow(()->new ResponseStatusException(HttpStatus.NOT_FOUND));}
@Transactional public WaitlistOffer offer(User me,Long id,LocalDateTime start,LocalDateTime end,Long employeeId,Integer validity){var r=get(me,id); if(!"ACTIVE".equals(r.getStatus())) throw new ResponseStatusException(HttpStatus.CONFLICT,"Request is not active"); BookingHold h=new BookingHold(); h.setCompany(me.getCompany()); h.setSlotStart(start); h.setSlotEnd(end); h.setExpiresAt(LocalDateTime.now().plusMinutes(validity==null?15:Math.max(1,validity))); h=holds.save(h); WaitlistOffer o=new WaitlistOffer(); o.setCompany(me.getCompany()); o.setRequest(r); o.setSlotStart(start); o.setSlotEnd(end); o.setExpiresAt(h.getExpiresAt()); o.setBookingHold(h); o=offers.save(o); r.setStatus("OFFERED"); requests.save(r); event(me,r,"OFFER_SENT","{\"expiresAt\":\""+o.getExpiresAt()+"\"}"); return o;} @Transactional public WaitlistRequest remove(User me,Long id){var r=get(me,id); r.setStatus("REMOVED"); requests.save(r); event(me,r,"REMOVED_BY_STAFF",null); return r;} @Transactional public WaitlistRequest convert(User me,Long id,Long bookingId){var r=get(me,id); r.setStatus("BOOKED"); requests.save(r); event(me,r,"CONVERTED_TO_BOOKING","{\"bookingId\":"+bookingId+"}"); return r;} public List<WaitlistRequest> matches(User me,Long serviceId,LocalDateTime start){return requests.findMatches(me.getCompany().getId(),serviceId,start.toLocalDate());} private void event(User me,WaitlistRequest r,String type,String details){WaitlistEvent e=new WaitlistEvent(); e.setCompany(me.getCompany());e.setRequest(r);e.setEventType(type);e.setActorType("STAFF");e.setActorId(String.valueOf(me.getId()));e.setDetailsJson(details);events.save(e);} }